const e = $input.all()[0].json || {};
const wf = (e.workflow && e.workflow.name) ? e.workflow.name : 'unknown workflow';
const exec = e.execution || {};
const trig = e.trigger || {};
const msg = (exec.error && exec.error.message) ? exec.error.message
  : (trig.error && trig.error.message) ? trig.error.message
  : 'No error message available';
const lastNode = exec.lastNodeExecuted || (trig.error && trig.error.node && trig.error.node.name) || 'n/a';
const url = exec.url || '';
const when = $now.toISO();

const subject = 'FarmGateIQ \u2014 Workflow error: ' + wf;
const html = '<p><b>A FarmGateIQ workflow failed.</b></p>'
  + '<p>Workflow: ' + wf + '<br>Error: ' + msg + '<br>Last node: ' + lastNode + '<br>Time: ' + when + '</p>'
  + (url ? '<p><a href="' + url + '">Open the execution in n8n</a></p>' : '')
  + '<p style="color:#888">Automated alert from WF-008 Error Handler. Set this workflow as the Error Workflow in each workflow\u2019s Settings.</p>';

return [{ json: { subject: subject, html: html, wf: wf, error_message: msg, last_node: lastNode } }];
